#include <bits/stdc++.h>
#define int long long
using namespace std;
const int INF = INT_MAX , N = 1e6 + 10;
struct node {
	int v , c , f;
};
vector < node > g[ N ];
priority_queue< pair< int , int > > pq;
int dis[ N ] , vis[ N ];
int n , m , s = 1;
int ans;
void dij( int F ) {
	for( int i = 0 ; i <= n ; i++ )
		vis[ i ] = 0;
	for( int i = 0 ; i <= n ; i++ )
		dis[ i ] = INF;
	dis[ s ] = 0;
	pq.push( { 0 , s } );
	while( !pq.empty() ) {
		int mi = pq.top().second;
		pq.pop();
		if( vis[ mi ] )
			continue;
		vis[ mi ] = 1;
		for( auto i : g[ mi ] ) {
			int v = i.v;
			int c = i.c;
			int f = i.f;
			if( f >= F && dis[ v ] > dis[ mi ] + c ) {
				dis[ v ] = dis[ mi ] + c;
				pq.push( { -dis[ v ] , v } );
			}
		}
	}
} 
signed main() {
	cin >> n >> m;
	for( int i = 1 ; i <= m ; i++ ) {
		int x , y , c , f;
		cin >> x >> y >> c >> f;
		g[ x ].push_back( { y , c , f } );
		g[ y ].push_back( { x , c , f } );
	}
	for( int i = 1 ; i <= 1000 ; i++ ) {
		dij( i );
		if( dis[n] != INF )
			ans = max( ans , 1000000 * i / dis[ n ] );
	}
	cout << ans;
	return 0;
}
